#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char A[100005], B[100005];
        scanf("%s", A);
        scanf("%s", B);
        long long Y = 0; // sum of y_i
        int M = 0; // count of differing positions
        for(int i=0;i<N;i++){
            int a = A[i]-'a';
            int b = B[i]-'a';
            int y = (a - b + 26) % 26; // cost of converting B->A (negative contribution)
            if(y!=0) M++;
            Y += y;
        }
        long long best = LLONG_MAX;
        long long k1 = Y/26; // floor
        long long k2 = (Y + 25)/26; // ceil
        if(k1<0) k1=0; if(k1>M) k1=M;
        if(k2<0) k2=0; if(k2>M) k2=M;
        long long s1 = -Y + 26*k1;
        long long s2 = -Y + 26*k2;
        if(llabs(s1) < best) best = llabs(s1);
        if(llabs(s2) < best) best = llabs(s2);
        printf("%lld\n", best);
    }
    return 0;
}

